  // ──────────────────────────────────────────────────
  // Internal request helper
  // ──────────────────────────────────────────────────

  Future<dynamic> _request(
    String method,
    String path, {
    Map<String, dynamic>? body,
    String? token,
  }) async {
    final uri = Uri.parse('$_baseUrl$path');
    final headers = <String, String>{
      'Content-Type': 'application/json',
      'Accept': 'application/json',
    };

    if (token != null) {
      headers['Authorization'] = 'Bearer $token';
    }

    final encodedBody = body != null ? jsonEncode(body) : null;
    late http.Response response;

    switch (method) {
      case 'GET':
        response = await _httpClient.get(uri, headers: headers);
      case 'POST':
        response = await _httpClient.post(uri, headers: headers, body: encodedBody);
      case 'PUT':
        response = await _httpClient.put(uri, headers: headers, body: encodedBody);
      case 'PATCH':
        response = await _httpClient.patch(uri, headers: headers, body: encodedBody);
      case 'DELETE':
        response = await _httpClient.delete(uri, headers: headers, body: encodedBody);
      default:
        throw AuthClientException('Unsupported HTTP method: $method');
    }

    if (response.statusCode < 200 || response.statusCode >= 300) {
      String errorMessage;
      int? errorCode;
      try {
        final errorBody = jsonDecode(response.body) as Map<String, dynamic>;
        errorMessage = (errorBody['error'] as String?) ??
            'Request failed with status ${response.statusCode}';
        errorCode = (errorBody['code'] as int?) ?? response.statusCode;
      } catch (_) {
        errorMessage = 'Request failed with status ${response.statusCode}';
        errorCode = response.statusCode;
      }
      throw AuthClientException(errorMessage, code: errorCode);
    }

    if (response.statusCode == 204 || response.body.isEmpty) {
      return null;
    }

    return jsonDecode(response.body);
  }
}

/// Exception thrown by the AuthSome API client.
class AuthClientException implements Exception {
  final String message;
  final int? code;

  const AuthClientException(this.message, {this.code});

  @override
  String toString() => 'AuthClientException($code): $message';
}
